using Contoso.Pricing;

namespace Contoso.Pricing.Tests;

[TestClass]
public sealed class PriceCalculatorTests
{
    private PriceCalculator _calculator = null!;

    [TestInitialize]
    public void Setup() => _calculator = new PriceCalculator();

    // ───────────────────────────────────────────────
    //  CalculateTotal – DataRow (compile-time data)
    // ───────────────────────────────────────────────

    [TestMethod]
    [DataRow(10.00, 1, 0.0,  10.00,  DisplayName = "Single item, no tax")]
    [DataRow(10.00, 2, 0.0,  20.00,  DisplayName = "Two items, no tax")]
    [DataRow(10.00, 1, 0.10, 11.00,  DisplayName = "Single item, 10% tax")]
    [DataRow(25.50, 3, 0.08, 82.62,  DisplayName = "Fractional price, 8% tax")]
    [DataRow(0.00,  5, 0.10, 0.00,   DisplayName = "Zero unit price")]
    [DataRow(99.99, 0, 0.10, 0.00,   DisplayName = "Zero quantity")]
    public void CalculateTotal_ReturnsExpected(
        double unitPrice, int quantity, double taxRate, double expected)
    {
        var result = _calculator.CalculateTotal(
            (decimal)unitPrice, quantity, (decimal)taxRate);

        Assert.AreEqual((decimal)expected, result);
    }

    // ───────────────────────────────────────────────
    //  CalculateTotal – invalid inputs
    // ───────────────────────────────────────────────

    [TestMethod]
    [DataRow(-1.00, 1,  0.10, DisplayName = "Negative unit price")]
    [DataRow(10.00, -1, 0.10, DisplayName = "Negative quantity")]
    [DataRow(10.00, 1,  -0.1, DisplayName = "Negative tax rate")]
    [DataRow(10.00, 1,  1.5,  DisplayName = "Tax rate above 1")]
    public void CalculateTotal_InvalidInput_Throws(
        double unitPrice, int quantity, double taxRate)
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(() =>
            _calculator.CalculateTotal(
                (decimal)unitPrice, quantity, (decimal)taxRate));
    }

    // ───────────────────────────────────────────────
    //  ApplyDiscount – DynamicData (runtime data)
    // ───────────────────────────────────────────────

    public static IEnumerable<object[]> DiscountTestCases
    {
        get
        {
            yield return [100m, 0m,   100.00m];   // no discount
            yield return [100m, 10m,  90.00m];    // 10% off
            yield return [100m, 50m,  50.00m];    // half off
            yield return [100m, 100m, 0.00m];     // free
            yield return [59.99m, 25m, 44.9925m]; // fractional result
            yield return [0m, 50m,    0.00m];     // zero price
        }
    }

    [TestMethod]
    [DynamicData(nameof(DiscountTestCases))]
    public void ApplyDiscount_ReturnsExpected(
        decimal price, decimal discountPercent, decimal expected)
    {
        var result = _calculator.ApplyDiscount(price, discountPercent);

        Assert.AreEqual(expected, result);
    }

    // ───────────────────────────────────────────────
    //  ApplyDiscount – DynamicData from method
    // ───────────────────────────────────────────────

    public static IEnumerable<object[]> InvalidDiscountCases()
    {
        yield return [100m, -1m];
        yield return [100m, 101m];
    }

    [TestMethod]
    [DynamicData(nameof(InvalidDiscountCases), DynamicDataSourceType.Method)]
    public void ApplyDiscount_InvalidDiscount_Throws(
        decimal price, decimal discountPercent)
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(() =>
            _calculator.ApplyDiscount(price, discountPercent));
    }

    // ───────────────────────────────────────────────
    //  FormatPrice – DataRow
    // ───────────────────────────────────────────────

    [TestMethod]
    [DataRow(19.99, "$", "$19.99",  DisplayName = "Dollar format")]
    [DataRow(19.99, "€", "€19.99",  DisplayName = "Euro format")]
    [DataRow(5.1,   "$", "$5.10",   DisplayName = "Pads to two decimals")]
    public void FormatPrice_ReturnsFormattedString(
        double price, string symbol, string expected)
    {
        var result = _calculator.FormatPrice((decimal)price, symbol);

        Assert.AreEqual(expected, result);
    }
}

